function barChart() {
  let width = 640;
  let height = 400;
  let x = d => d.name;
  let y = d => d.value;

  function chart(selection) {
    selection.each(function(data) {
      const xScale = d3.scaleBand()
        .domain(data.map(x))
        .range([0, width])
        .padding(0.1);
      const yScale = d3.scaleLinear()
        .domain([0, d3.max(data, y)])
        .range([height, 0]);

      const svg = d3.select(this)
        .selectAll("svg").data([data]).join("svg")
        .attr("viewBox", [0, 0, width, height]);

      svg.selectAll("rect")
        .data(data)
        .join("rect")
        .attr("x", d => xScale(x(d)))
        .attr("y", d => yScale(y(d)))
        .attr("height", d => height - yScale(y(d)))
        .attr("width", xScale.bandwidth());
    });
  }

  chart.width = v => (width = v, chart);
  chart.height = v => (height = v, chart);
  chart.x = v => (x = v, chart);
  chart.y = v => (y = v, chart);

  return chart;
}

